// Session represents a user session with relevant data
type Session struct {
	ID          string
	UserID      string
	Preferences map[string]string
	Permissions []string
	CreatedAt   time.Time
	ExpiresAt   time.Time
	LastAccess  time.Time
}

// SessionManager handles session lifecycle
type SessionManager struct {
	mu         sync.RWMutex
	sessions   map[string]*Session
	storageDir string
	maxAge     time.Duration
}

// NewSessionManager creates a new session manager with the given storage directory
func NewSessionManager(storageDir string, maxAge time.Duration) (*SessionManager, error) {
	// Validate and sanitize storage directory
	absDir, err := filepath.Abs(storageDir)
	if err != nil {
		return nil, fmt.Errorf("invalid storage directory: %w", err)
	}

	// Create storage directory with restrictive permissions
	if err := os.MkdirAll(absDir, 0700); err != nil {
		return nil, fmt.Errorf("failed to create storage directory: %w", err)
	}

	sm := &SessionManager{
		sessions:   make(map[string]*Session),
		storageDir: absDir,
		maxAge:     maxAge,
	}

	// Load existing sessions from disk
	if err := sm.loadAllSessions(); err != nil {
		log.Printf("Warning: error loading existing sessions: %v", err)
	}

	return sm, nil
}

// generateSessionID creates a cryptographically secure session ID
func generateSessionID() (string, error) {
	bytes := make([]byte, 32)
	if _, err := rand.Read(bytes); err != nil {
		return "", fmt.Errorf("failed to generate session ID: %w", err)
	}
	return hex.EncodeToString(bytes), nil
}

// validateSessionID checks that a session ID contains only valid hex characters
func validateSessionID(id string) error {
	if len(id) != 64 {
		return errors.New("invalid session ID length")
	}
	for _, c := range id {
		if !((c >= '0' && c <= '9') || (c >= 'a' && c <= 'f')) {
			return errors.New("invalid session ID characters")
		}
	}
	return nil
}

// sessionFilePath returns the safe file path for a session
func (sm *SessionManager) sessionFilePath(sessionID string) (string, error) {
	if err := validateSessionID(sessionID); err != nil {
		return "", err
	}
	// Use only the validated hex session ID as filename to prevent path traversal
	path := filepath.Join(sm.storageDir, sessionID+".gob")
	// Double-check the path is within our storage directory
	absPath, err := filepath.Abs(path)
	if err != nil {
		return "", fmt.Errorf("failed to resolve path: %w", err)
	}
	if !strings.HasPrefix(absPath, sm.storageDir+string(os.PathSeparator)) {
		return "", errors.New("path traversal detected")
	}
	return absPath, nil
}

// CreateSession creates a new session for the given user
func (sm *SessionManager) CreateSession(userID string, preferences map[string]string, permissions []string) (*Session, error) {
	sessionID, err := generateSessionID()
	if err != nil {
		return nil, err
	}

	now := time.Now()
	session := &Session{
		ID:          sessionID,
		UserID:      userID,
		Preferences: make(map[string]string),
		Permissions: make([]string, len(permissions)),
		CreatedAt:   now,
		ExpiresAt:   now.Add(sm.maxAge),
		LastAccess:  now,
	}

	// Deep copy preferences
	for k, v := range preferences {
		session.Preferences[k] = v
	}
	copy(session.Permissions, permissions)

	sm.mu.Lock()
	sm.sessions[sessionID] = session
	sm.mu.Unlock()

	// Persist to disk
	if err := sm.saveToDisk(session); err != nil {
		sm.mu.Lock()
		delete(sm.sessions, sessionID)
		sm.mu.Unlock()
		return nil, fmt.Errorf("failed to persist session: %w", err)
	}

	return session, nil
}

// GetSession retrieves a session by ID, checking expiration
func (sm *SessionManager) GetSession(sessionID string) (*Session, error) {
	if err := validateSessionID(sessionID); err != nil {
		return nil, err
	}

	sm.mu.RLock()
	session, exists := sm.sessions[sessionID]
	sm.mu.RUnlock()

	if !exists {
		// Try loading from disk
		var err error
		session, err = sm.loadFromDisk(sessionID)
		if err != nil {
			return nil, fmt.Errorf("session not found: %w", err)
		}
		sm.mu.Lock()
		sm.sessions[sessionID] = session
		sm.mu.Unlock()
	}

	// Check expiration
	if time.Now().After(session.ExpiresAt) {
		_ = sm.DestroySession(sessionID)
		return nil, errors.New("session expired")
	}

	// Update last access time
	sm.mu.Lock()
	session.LastAccess = time.Now()
	sm.mu.Unlock()

	// Persist updated access time
	if err := sm.saveToDisk(session); err != nil {
		log.Printf("Warning: failed to update session access time on disk: %v", err)
	}

	return session, nil
}

// UpdatePreferences updates the preferences for a session
func (sm *SessionManager) UpdatePreferences(sessionID string, preferences map[string]string) error {
	session, err := sm.GetSession(sessionID)
	if err != nil {
		return err
	}

	sm.mu.Lock()
	for k, v := range preferences {
		session.Preferences[k] = v
	}
	sm.mu.Unlock()

	return sm.saveToDisk(session)
}

// UpdatePermissions updates the permissions for a session
func (sm *SessionManager) UpdatePermissions(sessionID string, permissions []string) error {
	session, err := sm.GetSession(sessionID)
	if err != nil {
		return err
	}

	sm.mu.Lock()
	session.Permissions = make([]string, len(permissions))
	copy(session.Permissions, permissions)
	sm.mu.Unlock()

	return sm.saveToDisk(session)
}

// DestroySession removes a session from memory and disk
func (sm *SessionManager) DestroySession(sessionID string) error {
	if err := validateSessionID(sessionID); err != nil {
		return err
	}

	sm.mu.Lock()
	delete(sm.sessions, sessionID)
	sm.mu.Unlock()

	filePath, err := sm.sessionFilePath(sessionID)
	if err != nil {
		return err
	}

	if err := os.Remove(filePath); err != nil && !os.IsNotExist(err) {
		return fmt.Errorf("failed to remove session file: %w", err)
	}

	return nil
}

// CleanExpired removes all expired sessions
func (sm *SessionManager) CleanExpired() int {
	sm.mu.Lock()
	var expired []string
	now := time.Now()
	for id, session := range sm.sessions {
		if now.After(session.ExpiresAt) {
			expired = append(expired, id)
		}
	}
	for _, id := range expired {
		delete(sm.sessions, id)
	}
	sm.mu.Unlock()

	for _, id := range expired {
		filePath, err := sm.sessionFilePath(id)
		if err != nil {
			continue
		}
		_ = os.Remove(filePath)
	}

	return len(expired)
}

// saveToDisk persists a session to disk using gob encoding
func (sm *SessionManager) saveToDisk(session *Session) error {
	filePath, err := sm.sessionFilePath(session.ID)
	if err != nil {
		return err
	}

	// Write to a temporary file first, then rename for atomicity
	tmpFile, err := os.CreateTemp(sm.storageDir, "session-tmp-*.gob")
	if err != nil {
		return fmt.Errorf("failed to create temp file: %w", err)
	}
	tmpPath := tmpFile.Name()

	// Set restrictive permissions
	if err := tmpFile.Chmod(0600); err != nil {
		tmpFile.Close()
		os.Remove(tmpPath)
		return fmt.Errorf("failed to set file permissions: %w", err)
	}

	sm.mu.RLock()
	encoder := gob.NewEncoder(tmpFile)
	err = encoder.Encode(session)
	sm.mu.RUnlock()

	if err != nil {
		tmpFile.Close()
		os.Remove(tmpPath)
		return fmt.Errorf("failed to encode session: %w", err)
	}

	if err := tmpFile.Sync(); err != nil {
		tmpFile.Close()
		os.Remove(tmpPath)
		return fmt.Errorf("failed to sync file: %w", err)
	}

	if err := tmpFile.Close(); err != nil {
		os.Remove(tmpPath)
		return fmt.Errorf("failed to close temp file: %w", err)
	}

	if err := os.Rename(tmpPath, filePath); err != nil {
		os.Remove(tmpPath)
		return fmt.Errorf("failed to rename session file: %w", err)
	}

	return nil
}

// loadFromDisk loads a session from disk
func (sm *SessionManager) loadFromDisk(sessionID string) (*Session, error) {
	filePath, err := sm.sessionFilePath(sessionID)
	if err != nil {
		return nil, err
	}

	file, err := os.Open(filePath)
	if err != nil {
		return nil, fmt.Errorf("failed to open session file: %w", err)
	}
	defer file.Close()

	// Limit the size we'll read to prevent resource exhaustion (10MB max)
	info, err := file.Stat()
	if err != nil {
		return nil, fmt.Errorf("failed to stat session file: %w", err)
	}
	if info.Size() > 10*1024*1024 {
		return nil, errors.New("session file too large")
	}

	var session Session
	decoder := gob.NewDecoder(file)
	if err := decoder.Decode(&session); err != nil {
		return nil, fmt.Errorf("failed to decode session: %w", err)
	}

	// Validate the loaded session ID matches what we expected
	if session.ID != sessionID {
		return nil, errors.New("session ID mismatch")
	}

	return &session, nil
}

// loadAllSessions loads all sessions from the storage directory
func (sm *SessionManager) loadAllSessions() error {
	entries, err := os.ReadDir(sm.storageDir)
	if err != nil {
		return fmt.Errorf("failed to read storage directory: %w", err)
	}

	now := time.Now()
	for _, entry := range entries {
		if entry.IsDir() {
			continue
		}
		name := entry.Name()
		if !strings.HasSuffix(name, ".gob") {
			continue
		}
		// Skip temporary files
		if strings.HasPrefix(name, "session-tmp-") {
			continue
		}

		sessionID := strings.TrimSuffix(name, ".gob")
		if err := validateSessionID(sessionID); err != nil {
			log.Printf("Skipping invalid session file: %s", name)
			continue
		}

		session, err := sm.loadFromDisk(sessionID)
		if err != nil {
			log.Printf("Failed to load session %s: %v", sessionID, err)
			continue
		}

		// Skip expired sessions
		if now.After(session.ExpiresAt) {
			filePath, err := sm.sessionFilePath(sessionID)
			if err == nil {
				_ = os.Remove(filePath)
			}
			continue
		}

		sm.sessions[sessionID] = session
	}

	return nil
}

// ListActiveSessions returns a summary of active sessions (for admin purposes)
func (sm *SessionManager) ListActiveSessions() []map[string]interface{} {
	sm.mu.RLock()
	defer sm.mu.RUnlock()

	var result []map[string]interface{}
	now := time.Now()
	for _, session := range sm.sessions {
		if now.After(session.ExpiresAt) {
			continue
		}
		result = append(result, map[string]interface{}{
			"session_id":  session.ID[:8] + "...", // Only show partial ID
			"user_id":     session.UserID,
			"created_at":  session.CreatedAt,
			"expires_at":  session.ExpiresAt,
			"last_access": session.LastAccess,
		})
	}
	return result
}

